const path = require\('path'\);
const { PNG } = require\('pngjs'\);

const screenshotDir = path.join\(
  __dirname,
  'packages/charts/react-charts/stories/screenshots/vega_data'
\);

const files = fs.readdirSync\(screenshotDir\).filter\(f => f.endsWith\('.png'\)\);

const results = { PASS: [], ERROR: [], BLANK: [] };

for \(const file of files\) {
  const filePath = path.join\(screenshotDir, file\);
  const data = fs.readFileSync\(filePath\);
  const png = PNG.sync.read\(data\);
  const { width, height } = png;

  // --- ERROR detection ---
  // Count red pixels in right half \(x > 640\): R>200, G<80, B<80
  // Check if any rows have many red pixels \(error boundary box\)
  const rowRedCounts = {};
  for \(let y = 0; y < height; y++\) {
    rowRedCounts[y] = 0;
  }
  for \(let y = 0; y < height; y++\) {
    for \(let x = Math.max\(640, 0\); x < width; x++\) {
      const idx = \(y * width + x\) * 4;
      const r = png.data[idx];
      const g = png.data[idx + 1];
      const b = png.data[idx + 2];
      if \(r > 200 && g < 80 && b < 80\) {
        rowRedCounts[y]++;
      }
    }
  }
  // If there are rows with significant red pixels \(>=20 red pixels in a row\),
  // that indicates an error boundary box
  const redRows = Object.values\(rowRedCounts\).filter\(c => c >= 20\);
  if \(redRows.length >= 3\) {
    results.ERROR.push\(file\);
    continue;
  }

  // --- BLANK detection ---
  // Count "colored" pixels in chart preview area: x>530, y>230, y<620
  // A pixel is "colored" if NOT near-white \(all > 240\) AND NOT gray \(R,G,B within 10 of each other\)
  let coloredPixels = 0;
  const xMin = 530;
  const yMin = 230;
  const yMax = 620;
  for \(let y = yMin; y < Math.min\(yMax, height\); y++\) {
    for \(let x = xMin; x < width; x++\) {
      const idx = \(y * width + x\) * 4;
      const r = png.data[idx];
      const g = png.data[idx + 1];
      const b = png.data[idx + 2];
      // Check if near-white
      const isNearWhite = r > 240 && g > 240 && b > 240;
      // Check if gray \(all channels within 10 of each other\)
      const maxC = Math.max\(r, g, b\);
      const minC = Math.min\(r, g, b\);
      const isGray = \(maxC - minC\) <= 10;
      if \(!isNearWhite && !isGray\) {
        coloredPixels++;
      }
    }
  }
  if \(coloredPixels < 5000\) {
    results.BLANK.push\(file\);
    continue;
  }

  results.PASS.push\(file\);
}

